#include <cstring>
#include <map>
#include <string>
#include "esp_log.h"
#include "esp_partition.h"
#include "esp_spi_flash.h"
#include "cJSON.h"

#define TAG "Assets"
#define SECTOR_SIZE 4096

struct AssetInfo {
    uint32_t offset;
    uint32_t size;
};

class Assets {
private:
    const esp_partition_t* partition_;
    spi_flash_mmap_handle_t mmap_handle_;
    const char* mmap_root_;
    std::map<std::string, AssetInfo> assets_;

public:
    Assets() : partition_(nullptr), mmap_root_(nullptr) {
        // Step 1: Find and map the assets partition
        partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_ANY, ESP_PARTITION_SUBTYPE_ANY, "assets");
        if (partition_ == nullptr) {
            ESP_LOGI(TAG, "No assets partition found");
            return;
        }

        esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, 
                                           (const void**)&mmap_root_, &mmap_handle_);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mmap assets partition: %s", esp_err_to_name(err));
            return;
        }

        // Step 2: Load and validate index.json from mapped memory
        void* ptr = nullptr;
        size_t size = 0;
        if (!GetAssetData("index.json", ptr, size)) {
            ESP_LOGE(TAG, "Failed to load index.json");
            return;
        }

        cJSON* root = cJSON_ParseWithLength(static_cast<char*>(ptr), size);
        if (root == nullptr) {
            ESP_LOGE(TAG, "The index.json file is not valid");
            return;
        }

        cJSON* version = cJSON_GetObjectItem(root, "version");
        if (cJSON_IsNumber(version)) {
            if (version->valuedouble > 1) {
                ESP_LOGE(TAG, "The assets version %d is not supported, please upgrade the firmware", version->valueint);
                cJSON_Delete(root);
                return;
            }
        }

        // Step 3: Parse and register all assets listed in index.json
        cJSON* files = cJSON_GetObjectItem(root, "files");
        if (cJSON_IsArray(files)) {
            int count = cJSON_GetArraySize(files);
            for (int i = 0; i < count; ++i) {
                cJSON* entry = cJSON_GetArrayItem(files, i);
                if (!cJSON_IsObject(entry)) continue;

                cJSON* name_item = cJSON_GetObjectItem(entry, "name");
                cJSON* offset_item = cJSON_GetObjectItem(entry, "offset");
                cJSON* size_item = cJSON_GetObjectItem(entry, "size");

                if (cJSON_IsString(name_item) && cJSON_IsNumber(offset_item) && cJSON_IsNumber(size_item)) {
                    std::string name = name_item->valuestring;
                    uint32_t offset = offset_item->valuedouble;
                    uint32_t size = size_item->valuedouble;

                    assets_[name] = {offset, size};
                }
            }
        }

        cJSON_Delete(root);

        ESP_LOGI(TAG, "Assets initialized successfully.");
    }

    bool GetAssetData(const std::string &name, void *&ptr, size_t &size) {
        auto asset = assets_.find(name);
        if (asset == assets_.end()) {
            return false;
        }

        auto data = (const char *)(mmap_root_ + asset->second.offset);
        if (data[0] != 'Z' || data[1] != 'Z') {
            ESP_LOGE(TAG, "The asset %s is not valid with magic %02x%02x", name.c_str(), data[0], data[1]);
            return false;
        }

        ptr = static_cast<void *>(const_cast<char *>(data + 2));
        size = asset->second.size;
        return true;
    }
};

