bool InitializePartition()
{
    const char* TAG = "InitializePartition";

    // Step 1: Find the partition
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA,
        ESP_PARTITION_SUBTYPE_DATA_OTA,
        NULL
    );
    if (partition == NULL) {
        ESP_LOGE(TAG, "Partition not found");
        return false;
    }

    // Step 2: Map the partition into memory
    spi_flash_mmap_handle_t mmap_handle = 0;
    const void* mapped_ptr = nullptr;
    esp_err_t err = esp_partition_mmap(
        partition,
        0,
        partition->size,
        SPI_FLASH_MMAP_DATA,
        &mapped_ptr,
        &mmap_handle
    );
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map partition: %s", esp_err_to_name(err));
        return false;
    }

    bool result = false;

    do {
        // Step 3: Parse asset table/index
        struct mmap_assets_table {
            char asset_name[32];
            uint32_t asset_size;
            uint32_t asset_offset;
        };

        auto asset_entry = static_cast<const mmap_assets_table*>(mapped_ptr);

        // Simple end condition: empty string name
        while (strlen(asset_entry->asset_name) > 0 &&
               reinterpret_cast<const uint8_t*>(asset_entry) <
                   (reinterpret_cast<const uint8_t*>(mapped_ptr) + partition->size)) {

            // Store asset info (assuming assets_ map exists)
            assets_[asset_entry->asset_name] = {
                .size = asset_entry->asset_size,
                .offset = asset_entry->asset_offset
            };
            asset_entry++;
        }

        // Optional: Validate checksum of asset table
        uint32_t table_length = reinterpret_cast<const uint8_t*>(asset_entry) -
                                reinterpret_cast<const uint8_t*>(mapped_ptr);
        uint32_t expected_checksum = *reinterpret_cast<const uint32_t*>(
            reinterpret_cast<const uint8_t*>(mapped_ptr) + table_length
        );

        uint32_t calculated_checksum = CalculateChecksum(
            static_cast<const char*>(mapped_ptr),
            table_length
        );

        if (calculated_checksum != expected_checksum) {
            ESP_LOGE(TAG, "Asset table checksum mismatch");
            break;
        }

        result = true;

    } while (false);

    // Step 4: Unmap memory regardless of success/failure
    if (mmap_handle != 0) {
        esp_partition_munmap(mmap_handle);
        mmap_handle = 0;
    }

    return result;
}

