bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    const char* TAG = "Assets";
    ESP_LOGI(TAG, "Starting download from %s", url.c_str());

    // Step 1: Find the assets partition
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_ANY, ESP_PARTITION_SUBTYPE_ANY, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Step 2: Initialize HTTP client
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.method = HTTP_METHOD_GET;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0 || (size_t)content_length > partition_->size) {
        ESP_LOGE(TAG, "Invalid content length or exceeds partition size (%d)", content_length);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Step 3: Prepare flash for writing
    size_t offset = 0;
    const size_t sector_size = SPI_FLASH_SEC_SIZE;
    char buffer[512]; // Small buffer for streaming data
    size_t total_written = 0;
    auto start_time = esp_timer_get_time();
    size_t last_reported_progress = 0;

    // Pre-erase entire partition range to avoid partial corruption
    for (size_t addr = 0; addr < content_length; addr += sector_size) {
        esp_partition_erase_range(partition_, addr, sector_size);
    }

    // Step 4: Stream and write data
    while (total_written < (size_t)content_length) {
        int read_len = esp_http_client_read(client, buffer, sizeof(buffer));
        if (read_len < 0) {
            ESP_LOGE(TAG, "HTTP read error");
            break;
        } else if (read_len == 0) {
            // End of stream
            break;
        }

        // Write to flash
        err = esp_partition_write(partition_, total_written, buffer, read_len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Flash write failed at offset %d: %s", total_written, esp_err_to_name(err));
            break;
        }

        total_written += read_len;

        // Throttle progress reporting to reduce overhead
        auto now = esp_timer_get_time();
        double elapsed_sec = (now - start_time) / 1e6;
        size_t speed_bps = elapsed_sec > 0 ? total_written / elapsed_sec : 0;

        int current_progress = (total_written * 100) / content_length;
        if ((current_progress - last_reported_progress) >= 5 || current_progress == 100) {
            progress_callback(current_progress, speed_bps);
            last_reported_progress = current_progress;
        }
    }

    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    if (total_written != (size_t)content_length) {
        ESP_LOGE(TAG, "Incomplete download: expected=%d, written=%d", content_length, total_written);
        return false;
    }

    ESP_LOGI(TAG, "Download completed successfully");
    return true;
}

