        return false;
    }

    const cJSON *version_item = cJSON_GetObjectItemCaseSensitive(json_root, "version");
    if (!cJSON_IsString(version_item) || version_item->valuestring == nullptr) {
        ESP_LOGE(TAG, "Invalid 'version' field in response.");
        cJSON_Delete(json_root);
        return false;
