#include <esp_log.h>
#include <esp_ota_ops.h>
#include <chrono>
#include <sstream>

#define TAG "Ota"

bool Ota::Upgrade(const std::string& firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    // Step 1: Check Version (Assume version comes from somewhere like query param or known endpoint)
    // For simplicity assume remote version can be parsed from URL or fetched separately.
    std::string remote_version = "2.0.0"; // Placeholder — ideally extracted from server or URL

    if (!has_serial_number_) {
        ESP_LOGW(TAG, "No serial number available. Cannot proceed without activation.");
        return false;
    }

    if (!IsNewVersionAvailable(SystemInfo::GetFirmwareVersion(), remote_version)) {
        ESP_LOGI(TAG, "Current firmware (%s) is equal or newer than remote (%s)", 
                 SystemInfo::GetFirmwareVersion().c_str(), remote_version.c_str());
        return false;
    }

    // Step 2: Initialize HTTP Client
    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return false;
    }

    // Step 3: Start HTTP GET Request
    int status_code = http->Get(firmware_url);
    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP GET failed with status code: %d", status_code);
        return false;
    }

    // Step 4: Get Next OTA Partition
    const esp_partition_t* partition = esp_ota_get_next_update_partition(NULL);
    if (!partition) {
        ESP_LOGE(TAG, "Failed to find next OTA partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             partition->subtype, partition->address);

    // Step 5: Begin OTA Update
    esp_ota_handle_t ota_handle = 0;
    esp_err_t err = esp_ota_begin(partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Step 6: Download and Flash Firmware Binary
    uint8_t buffer[1024];
    size_t total_bytes_written = 0;
    size_t bytes_per_second = 0;
    int last_progress_reported = 0;

    auto start_time = std::chrono::steady_clock::now();

    while (true) {
        int read_len = http->Read(buffer, sizeof(buffer));
        if (read_len < 0) {
            ESP_LOGE(TAG, "HTTP read error");
            esp_ota_abort(ota_handle);
            return false;
        }

        if (read_len == 0) break; // EOF

        err = esp_ota_write(ota_handle, buffer, read_len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            esp_ota_abort(ota_handle);
            return false;
        }

        total_bytes_written += read_len;

        // Compute elapsed time and speed
        auto now = std::chrono::steady_clock::now();
        auto duration_ms = std::chrono::duration_cast<std::chrono::milliseconds>(now - start_time).count();
        if (duration_ms >= 1000) { // Update every second
            bytes_per_second = static_cast<size_t>((total_bytes_written * 1000ULL) / duration_ms);
        }

        // Compute progress
        size_t content_length = http->GetContentLength();
        int progress = content_length > 0 ? static_cast<int>((total_bytes_written * 100) / content_length) : 0;

        // Throttle progress reports
        if (progress != last_progress_reported && callback) {
            callback(progress, bytes_per_second);
            last_progress_reported = progress;
        }
    }

    // Final progress update
    if (callback) {
        callback(100, bytes_per_second);
    }

    // Step 7: Finish OTA
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Step 8: Set Boot Partition
    err = esp_ota_set_boot_partition(partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade successful. Rebooting...");
    esp_restart();

    return true;
}

