    http->SetContent(std::move(json_payload));

    if (!http->Open("POST", url)) {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection, code=0x%x", last_error);
        return static_cast<esp_err_t>(last_error);
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200) {
        ESP_LOGE(TAG, "Activation failed, status code: %d", status_code);
        http->Close();
        return static_cast<esp_err_t>(status_code);
    }

    std::string response = http->ReadAll();
    http->Close();

    // Parse response
    cJSON *root = cJSON_Parse(response.c_str());
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse activation response");
        return ESP_ERR_INVALID_RESPONSE;
    }

    cJSON *result_item = cJSON_GetObjectItem(root, "result");
    if (cJSON_IsString(result_item)) {
        activation_result_ = result_item->valuestring;
    } else {
        ESP_LOGW(TAG, "No 'result' field found in activation response");
    }

    cJSON_Delete(root);

    ESP_LOGI(TAG, "Activation completed successfully with result: %s", activation_result_.c_str());
    return ESP_OK;
}

