esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
    const size_t buf_size = 2048;
    char *buf_before = (char *)calloc(1, buf_size);
    char *buf_after = (char *)calloc(1, buf_size);

    if (!buf_before || !buf_after) {
        ESP_LOGE(TAG, "Failed to allocate buffers");
        free(buf_before);
        free(buf_after);
        return ESP_ERR_NO_MEM;
    }

    // Take initial snapshot
    vTaskGetRunTimeStats(buf_before);

    // Wait for specified duration
    vTaskDelay(xTicksToWait);

    // Take second snapshot
    vTaskGetRunTimeStats(buf_after);

    // Parse both buffers into maps: task name -> runtime counter
    std::map<std::string, uint32_t> before_stats, after_stats;

    auto parse_buffer = [](const char* buffer, std::map<std::string, uint32_t>& stats_map) {
        char* dup = strdup(buffer);
        char* line = strtok(dup, "\n");
        while (line != nullptr) {
            char* token = strtok(line, "\t");
            if (token == nullptr) continue;

            std::string task_name(token);
            // Skip state, priority, stack, num
            for (int i = 0; i < 4; ++i) {
                token = strtok(nullptr, "\t");
                if (token == nullptr) break;
            }
            if (token != nullptr) {
                uint32_t runtime = strtoul(token, nullptr, 10);
                stats_map[task_name] = runtime;
            }
            line = strtok(nullptr, "\n");
        }
        free(dup);
    };

    parse_buffer(buf_before, before_stats);
    parse_buffer(buf_after, after_stats);

    // Calculate total elapsed runtime counters
    uint32_t total_elapsed = 0;
    for (const auto& pair : after_stats) {
        const std::string& name = pair.first;
        uint32_t after_val = pair.second;
        auto it = before_stats.find(name);
        if (it != before_stats.end()) {
            uint32_t before_val = it->second;
            total_elapsed += (after_val - before_val);
        }
    }

    ESP_LOGI(TAG, "CPU Usage over %lu ticks:", xTicksToWait);
    for (const auto& pair : after_stats) {
        const std::string& name = pair.first;
        uint32_t after_val = pair.second;
        auto it = before_stats.find(name);
        if (it != before_stats.end()) {
            uint32_t before_val = it->second;
            uint32_t diff = after_val - before_val;
            float cpu_percent = (total_elapsed > 0) ? ((float)diff / total_elapsed) * 100.0f : 0.0f;
            ESP_LOGI(TAG, "%s: %.2f%%", name.c_str(), cpu_percent);
        } else {
            ESP_LOGI(TAG, "%s: Created during measurement", name.c_str());
        }
    }

    for (const auto& pair : before_stats) {
        const std::string& name = pair.first;
        if (after_stats.find(name) == after_stats.end()) {
            ESP_LOGI(TAG, "%s: Deleted during measurement", name.c_str());
        }
    }

    free(buf_before);
    free(buf_after);
    return ESP_OK;
}

