#define TAG "AudioDebugger"

// Example of initializing a UDP client socket
int init_udp_socket(const char* server_ip, int port, struct sockaddr_in& server_addr) {
    int sockfd = socket(AF_INET, SOCK_DGRAM, 0);
    if (sockfd < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return -1;
    }

    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(port);

    if (inet_aton(server_ip, &server_addr.sin_addr) == 0) {
        ESP_LOGE(TAG, "Invalid server IP address: %s", server_ip);
        close(sockfd);
        return -1;
    }

    ESP_LOGI(TAG, "UDP socket initialized for %s:%d", server_ip, port);
    return sockfd;
}
#endif
