    const TickType_t xMaxBlockTime = pdMS_TO_TICKS(100);
    EventBits_t uxBits;

    while (true) {
        // Wait for the detection running event bit
        uxBits = xEventGroupWaitBits(event_group_, DETECTION_RUNNING_EVENT, pdFALSE, pdTRUE, xMaxBlockTime);

        if ((uxBits & DETECTION_RUNNING_EVENT) != 0) {
