bool CustomWakeWord::ParseWakenetModelConfig() {
    void* ptr = nullptr;
    size_t size = 0;

    // Step 1: Get asset data for index.json
    if (!GetAssetData("index.json", ptr, size)) {
        ESP_LOGE(TAG, "Failed to get index.json asset data");
        return false;
    }

    // Step 2: Parse JSON content
    cJSON* root = cJSON_ParseWithLength(static_cast<char*>(ptr), size);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json as valid JSON");
        return false;
    }

    // Step 3: Extract language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (cJSON_IsString(language_item)) {
        language_ = language_item->valuestring;
    } else {
        ESP_LOGE(TAG, "Missing or invalid 'language' in index.json");
        cJSON_Delete(root);
        return false;
    }

    // Step 4: Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (cJSON_IsNumber(duration_item)) {
        duration_ = static_cast<int>(duration_item->valuedouble);
    } else {
        ESP_LOGE(TAG, "Missing or invalid 'duration' in index.json");
        cJSON_Delete(root);
        return false;
    }

    // Step 5: Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (cJSON_IsNumber(threshold_item)) {
        threshold_ = static_cast<float>(threshold_item->valuedouble);
    } else {
        ESP_LOGE(TAG, "Missing or invalid 'threshold' in index.json");
        cJSON_Delete(root);
        return false;
    }

    // Step 6: Process commands array
    cJSON* commands_array = cJSON_GetObjectItem(root, "commands");
    if (!cJSON_IsArray(commands_array)) {
        ESP_LOGE(TAG, "Missing or invalid 'commands' array in index.json");
        cJSON_Delete(root);
        return false;
    }

    int num_commands = cJSON_GetArraySize(commands_array);
    commands_.clear();
    commands_.reserve(num_commands);

    for (int i = 0; i < num_commands; ++i) {
        cJSON* cmd_obj = cJSON_GetArrayItem(commands_array, i);
        if (!cmd_obj || !cJSON_IsObject(cmd_obj)) {
            ESP_LOGW(TAG, "Skipping invalid command at index %d", i);
            continue;
        }

        cJSON* command_field = cJSON_GetObjectItem(cmd_obj, "command");
        cJSON* text_field = cJSON_GetObjectItem(cmd_obj, "text");
        cJSON* action_field = cJSON_GetObjectItem(cmd_obj, "action");

        if (!cJSON_IsString(command_field) ||
            !cJSON_IsString(text_field) ||
            !cJSON_IsString(action_field)) {
            ESP_LOGW(TAG, "Command at index %d has missing/invalid fields", i);
            continue;
        }

        WakeWordCommand cmd;
        cmd.command = command_field->valuestring;
        cmd.text = text_field->valuestring;
        cmd.action = action_field->valuestring;

        commands_.push_back(std::move(cmd));

        ESP_LOGI(TAG, "Loaded command: %s | Text: %s | Action: %s",
                 cmd.command.c_str(),
                 cmd.text.c_str(),
                 cmd.action.c_str());
    }

    // Final cleanup
    cJSON_Delete(root);

    ESP_LOGI(TAG, "Successfully loaded wakenet model config: lang=%s, dur=%d, thr=%.2f, cmds=%d",
             language_.c_str(), duration_, threshold_, static_cast<int>(commands_.size()));

    return true;
}

