void StoreWakeWordData(const std::vector<int16_t>& data) {
    if (data.empty()) {
        return;
    }

    // Lock to ensure thread safety when accessing wake_word_pcm_
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Add new chunk of data
    wake_word_pcm_.emplace_back(data);

    // Compute current total number of samples
    size_t total_samples = 0;
    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
    }

    // Remove oldest chunks until we're under the sample limit
    while (total_samples > max_samples && !wake_word_pcm_.empty()) {
        total_samples -= wake_word_pcm_.front().size();
        wake_word_pcm_.pop_front();
    }
}

