void ReceiveWifiCredentialsFromAudio(Application *app, WifiManager *wifi_manager, Display *display, size_t input_channels) {
    ESP_LOGI(kLogTag, "Starting Wi-Fi credential reception via audio...");

    // Constants for expected packet structure
    constexpr float kSampleRate = 8000.0f;         // Example sample rate
    constexpr size_t kChunkSize = 512;             // Number of samples per read
    constexpr float kThreshold = 0.5f;             // Probability threshold for bit detection
    constexpr size_t kExpectedHeaderLength = 4;    // For example "WIFI"
    constexpr size_t kMinPacketLength = 16;        // Minimum number of bytes including header/checksum

    AudioSignalProcessor processor(kSampleRate);   // Initialize with known sample rate
    AudioDataBuffer buffer;

    std::vector<int16_t> raw_samples(kChunkSize * input_channels);
    bool credentials_received = false;

    display->ShowMessage("Listening for Wi-Fi credentials...");

    while (!credentials_received && !app->ShouldExit()) {
        // Simulate reading from audio input (replace with actual driver call)
        size_t samples_read = app->ReadAudioSamples(raw_samples.data(), kChunkSize * input_channels);

        if (samples_read == 0) continue;

        // Convert to mono if necessary
        std::vector<float> mono_samples;
        mono_samples.reserve(kChunkSize);

        for (size_t i = 0; i < samples_read; i += input_channels) {
            float sum = 0.0f;
            for (size_t ch = 0; ch < input_channels; ++ch) {
                sum += static_cast<float>(raw_samples[i + ch]) / 32768.0f;
            }
            mono_samples.push_back(sum / static_cast<float>(input_channels));
        }

        // Process audio into probability values (bit likelihoods)
        std::vector<float> processed_probs = processor.ProcessAudioSamples(mono_samples);

        // Try to decode bits from probabilities
        if (buffer.ProcessProbabilityData(processed_probs, kThreshold)) {
            std::string decoded_text = buffer.GetDecodedText();

            ESP_LOGI(kLogTag, "Decoded Text: %s", decoded_text.c_str());

            if (decoded_text.length() >= kMinPacketLength &&
                decoded_text.substr(0, kExpectedHeaderLength) == "WIFI") {

                // Extract payload excluding header and last byte (checksum)
                std::string payload = decoded_text.substr(kExpectedHeaderLength,
                                                          decoded_text.length() - kExpectedHeaderLength - 1);
                uint8_t received_checksum = static_cast<uint8_t>(decoded_text.back());

                // Compute local checksum
                uint8_t computed_checksum = AudioDataBuffer::CalculateChecksum(payload);

                if (computed_checksum == received_checksum) {
                    ESP_LOGI(kLogTag, "Checksum OK. Proceeding with network setup.");

                    // Assume payload format: ssid\0password
                    size_t null_pos = payload.find('\0');
                    if (null_pos != std::string::npos) {
                        std::string ssid = payload.substr(0, null_pos);
                        std::string password = payload.substr(null_pos + 1);

