                        display->ShowMessage("Error: Bad Format");
                    }
                } else {
                    ESP_LOGW(kLogTag, "Checksum mismatch!");
                    display->ShowMessage("Error: Corrupted Data");
                }

                buffer.Reset();  // Prepare for next packet
            }
        }
    }

    if (credentials_received) {
        display->ShowMessage("Connected successfully!");
        ESP_LOGI(kLogTag, "Wi-Fi credentials received and applied.");
    } else {
        display->ShowMessage("Cancelled or timeout.");
        ESP_LOGI(kLogTag, "Reception cancelled or timed out.");
    }
}

