```cpp
class FrequencyDetector {
private:
    float cos_coefficient_;
    float sin_coefficient_;
    float filter_coefficient_;
    std::deque<float> state_buffer_; // Stores previous outputs S[n-2], S[n-1]

public:
    void ProcessSample(float sample) {
        // Compute current output: S[n] = sample + filter_coefficient_ * S[n-1] - S[n-2]
        float s_minus_2 = state_buffer_[0];
        float s_minus_1 = state_buffer_[1];
        float current_output = sample + filter_coefficient_ * s_minus_1 - s_minus_2;

        // Update state buffer
        state_buffer_[0] = s_minus_1;
        state_buffer_[1] = current_output;
    }

    void Reset() {
        state_buffer_[0] = 0.0f;
        state_buffer_[1] = 0.0f;
    }
};
