```cpp
float FrequencyDetector::GetAmplitude() const
{
    if (state_buffer_.size() < 2)
    {
        return 0.0f;
    }

    // Access the last two processed samples
    auto it = state_buffer_.rbegin();
    float s_curr = *it;
    float s_prev = *(++it);

    // Compute real and imaginary parts
    float real = s_curr - s_prev * cos_coefficient_;
    float imag = s_prev * sin_coefficient_;

    // Calculate magnitude and normalize
