                        }
                    }
                    break;

                case DataReceptionState::kReceiving:
                    identifier_buffer_.push_back(bit);
                    if (identifier_buffer_.size() == kDefaultEndTransmissionPattern.size())
                    {
                        if (std::vector<uint8_t>(identifier_buffer_.begin(), identifier_buffer_.end()) == kDefaultEndTransmissionPattern)
