                            std::vector<uint8_t> trimmed_bits(bit_buffer_.begin(), bit_buffer_.begin() + complete_bits_count);

                            std::vector<uint8_t> bytes = ConvertBitsToBytes(trimmed_bits);

                            if (!bytes.empty() && enable_checksum_validation_)
                            {
                                size_t payload_length = bytes.size() - 1;
                                uint8_t received_checksum = bytes.back();

                                std::string decoded_string(bytes.begin(), bytes.begin() + payload_length);
