```cpp
std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t> &bits) const
{
    std::vector<uint8_t> bytes;
    size_t num_bits = bits.size();
    size_t num_bytes = (num_bits + 7) / 8; // Round up to nearest byte
    bytes.reserve(num_bytes);

    for (size_t i = 0; i < num_bits; i += 8)
    {
        uint8_t byte = 0;
        for (size_t j = 0; j < 8 && (i + j) < num_bits; ++j)
        {
            if (bits[i + j])
            {
                byte |= (1 << j); // Set bit j if bits[i+j] is non-zero (assuming LSB first)
            }
        }
        bytes.push_back(byte);
    }

    return bytes;
}
