void WifiBoard::TryWifiConnect()
{
    auto& wifi_manager = WifiManager::GetInstance();

    // Avoid re-entry while already trying to connect
    if (is_connecting_) {
        return;
    }
    is_connecting_ = true;

    // Stop any existing timer to prevent overlap
    esp_timer_stop(connect_timer_);

    // Begin connection process
    wifi_manager.StartStation();

    // Set up timeout for connection attempt
    esp_timer_start_once(connect_timer_, pdMS_TO_TICKS(15000)); // 15 seconds timeout

    // Trigger connecting event
    OnNetworkEvent(NetworkEvent::Connecting, wifi_manager.GetSsid());

    // Optionally, create a delayed task to enter config mode on failure
    xTaskCreate([](void* arg) {
        auto* board = static_cast<WifiBoard*>(arg);

        // Wait for connection result (simulate waiting)
        vTaskDelay(pdMS_TO_TICKS(16000)); // Slightly longer than timer

        // Check if still not connected
        if (board->is_connecting_) {
            ESP_LOGW(TAG, "WiFi connection timed out. Entering config mode.");

            // Gracefully stop station
            WifiManager::GetInstance().StopStation();

            // Enter config mode
            board->StartWifiConfigMode();
        }

        vTaskDelete(NULL);
    }, "wifi_retry_task", 4096, this, 2, NULL);
}

