void SingleLed::StartBlinkTask(int count, int interval_ms)
{
    std::lock_guard<std::mutex> lock(mutex_);

    // Set the blink counter: double the count because one full blink is two toggles (on/off)
    blink_counter_ = (count == BLINK_INFINITE) ? BLINK_INFINITE : count * 2;

    // Convert interval from ms to microseconds for esp_timer
    int64_t interval_us = static_cast<int64_t>(interval_ms) * 1000;

    // Stop any existing timer before restarting
    esp_timer_stop(blink_timer_);

    // Start the timer periodically with the given interval
    ESP_ERROR_CHECK(esp_timer_start_periodic(blink_timer_, interval_us));
}

