    auto* header = reinterpret_cast<UdpAudioPacket*>(out_buffer.data());
    header->version = htons(0x0001);
    header->type = htons(AUDIO_PACKET_TYPE);  // Assume predefined constant
    header->reserved = 0;
    header->timestamp = htonl(packet->timestamp);
    header->sequence_number = htonl(local_sequence_);
    header->payload_size = htonl(PAYLOAD_SIZE);

    // Perform AES-CTR encryption
    size_t nc_off = 0;
    unsigned char ctr_buf[16] = {0};
    unsigned char stream_block[16] = {0};

    int ret = mbedtls_aes_crypt_ctr(
        &aes_ctx_,
        PAYLOAD_SIZE,
        &nc_off,
        nonce,
        ctr_buf,
        packet->payload.data(),
        header->payload
    );

    if (ret != 0) {
        return false;
    }

    // Send over UDP
    return udp_->Send(out_buffer.data(), TOTAL_SIZE);
}

