void MqttProtocol::ParseServerHello(const cJSON *root)
{
    // Validate input
    if (root == nullptr) {
        ESP_LOGE(TAG, "Invalid JSON root");
        return;
    }

    // Extract encryption key (as hex string)
    cJSON* key_item = cJSON_GetObjectItem(root, "encryption_key");
    if (!cJSON_IsString(key_item) || key_item->valuestring == nullptr) {
        ESP_LOGE(TAG, "Missing or invalid 'encryption_key'");
        return;
    }

    std::string hex_key = key_item->valuestring;

    // Decode hex string into binary
    std::string decoded_key = DecodeHexString(hex_key);

    // Ensure decoded key has valid size (e.g., 128-bit = 16 bytes)
    if (decoded_key.size() != 16) {
        ESP_LOGE(TAG, "Invalid key length: %d bytes", (int)decoded_key.size());
        return;
    }

    // Initialize AES encryption context
    mbedtls_aes_init(&aes_ctx_);
    int ret = mbedtls_aes_setkey_enc(&aes_ctx_, 
                                     reinterpret_cast<const unsigned char*>(decoded_key.data()), 
                                     static_cast<unsigned int>(decoded_key.size() * 8));
    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to set AES key, mbedtls error: %d", ret);
        return;
    }

    // Signal completion so other tasks can proceed
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

    ESP_LOGI(TAG, "Successfully processed ServerHello message.");
}

