bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        ESP_LOGW(TAG, "WebSocket not connected. Cannot send audio.");
        return false;
    }

    const size_t payload_size = packet->payload.size();
    if (payload_size == 0)
    {
        ESP_LOGW(TAG, "Empty audio packet received. Nothing to send.");
        return true; // Not necessarily an error
    }

    std::vector<uint8_t> buffer;

    if (version_ == 2)
    {
        BinaryProtocol2 bp2_hdr{};
        bp2_hdr.version = htons(2);
        bp2_hdr.type = htons(1); // Assuming type 1 for audio
        bp2_hdr.timestamp = htonl(packet->timestamp);
        bp2_hdr.payload_size = htonl(payload_size);

        const uint8_t* hdr_bytes = reinterpret_cast<const uint8_t*>(&bp2_hdr);
        buffer.insert(buffer.end(), hdr_bytes, hdr_bytes + sizeof(bp2_hdr));
        buffer.insert(buffer.end(), packet->payload.begin(), packet->payload.end());
    }
    else if (version_ == 3)
    {
        BinaryProtocol3 bp3_hdr{};
        bp3_hdr.type = 1; // Assuming type 1 for audio
        bp3_hdr.payload_size = htons(payload_size);

        const uint8_t* hdr_bytes = reinterpret_cast<const uint8_t*>(&bp3_hdr);
        buffer.insert(buffer.end(), hdr_bytes, hdr_bytes + sizeof(bp3_hdr));
        buffer.insert(buffer.end(), packet->payload.begin(), packet->payload.end());
    }
    else
    {
        // Fallback: Just send the raw payload
        buffer = std::move(packet->payload);
    }

    if (!websocket_->Send(buffer.data(), buffer.size(), WS_OPCODE_BINARY))
    {
        ESP_LOGE(TAG, "Failed to send audio packet over WebSocket.");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

