#### 2. **Binary Protocol Handling (Versions 2 and 3)**
The `SendAudio()` method shows how to handle different binary protocol versions with appropriate byte order conversion:

```cpp
void WebsocketProtocol::HandleIncomingAudioPacket(const uint8_t* data, size_t len)
{
    if (len < sizeof(BinaryProtocol2)) {
        ESP_LOGE(TAG, "Invalid packet size");
        return;
    }

    if (version_ == 2) {
        const BinaryProtocol2* bp2 = reinterpret_cast<const BinaryProtocol2*>(data);
        uint16_t version = ntohs(bp2->version);
        uint32_t timestamp = ntohl(bp2->timestamp);
        uint32_t payload_size = ntohl(bp2->payload_size);

        if (len < sizeof(BinaryProtocol2) + payload_size) {
            ESP_LOGE(TAG, "Incomplete packet");
            return;
        }

        ProcessAudioPayload(bp2->payload, payload_size, timestamp);
    }
    else if (version_ == 3) {
        const BinaryProtocol3* bp3 = reinterpret_cast<const BinaryProtocol3*>(data);
        uint16_t payload_size = ntohs(bp3->payload_size);

        if (len < sizeof(BinaryProtocol3) + payload_size) {
            ESP_LOGE(TAG, "Incomplete packet");
            return;
        }

        ProcessAudioPayload(bp3->payload, payload_size, 0); // No timestamp in v3
    }
    else {
        ProcessAudioPayload(data, len, 0); // Raw payload
    }
}
```

